class DisjointSet {
    vector<int> parent, rankv;

public:
    DisjointSet(int n) {
        parent.resize(n);
        rankv.resize(n, 0);
        for (int i = 0; i < n; i++)
            parent[i] = i;
    }

    int findParent(int x) {
        if (parent[x] != x)
            parent[x] = findParent(parent[x]);
        return parent[x];
    }

    void unionSet(int a, int b) {
        int pa = findParent(a);
        int pb = findParent(b);
        if (pa == pb) return;

        if (rankv[pa] < rankv[pb]) {
            parent[pa] = pb;
        } else if (rankv[pa] > rankv[pb]) {
            parent[pb] = pa;
        } else {
            parent[pb] = pa;
            rankv[pa]++;
        }
    }
};

vector<vector<string>> mergeAccounts(vector<vector<string>>& accountLists) {
    int n = accountLists.size();
    DisjointSet ds(n);

    unordered_map<string, int> emailToAccount;

    // Union accounts with common emails
    for (int i = 0; i < n; i++) {
        for (int j = 1; j < accountLists[i].size(); j++) {
            string email = accountLists[i][j];
            if (emailToAccount.count(email)) {
                ds.unionSet(i, emailToAccount[email]);
            } else {
                emailToAccount[email] = i;
            }
        }
    }

    // Collect emails by root parent
    unordered_map<int, set<string>> groupedEmails;
    for (auto& it : emailToAccount) {
        int root = ds.findParent(it.second);
        groupedEmails[root].insert(it.first);
    }

    // Build merged result
    vector<vector<string>> result;
    for (auto& it : groupedEmails) {
        int root = it.first;
        vector<string> merged;
        merged.push_back(accountLists[root][0]); // name
        for (auto& email : it.second)
            merged.push_back(email);
        result.push_back(merged);
    }

    return result;
}

