        ds->parent[x] = findSet(ds, ds->parent[x]);
    return ds->parent[x];
}

void unionSet(DisjointSet* ds, int a, int b) {
    int pa = findSet(ds, a);
    int pb = findSet(ds, b);
    if (pa == pb) return;

    if (ds->rank[pa] < ds->rank[pb])
        ds->parent[pa] = pb;
    else if (ds->rank[pa] > ds->rank[pb])
        ds->parent[pb] = pa;
    else {
        ds->parent[pb] = pa;
        ds->rank[pa]++;
    }
}

int cmp(const void* a, const void* b) {
    return strcmp(*(char**)a, *(char**)b);
}

char*** mergeAccounts(
    char*** accounts,
    int accountsSize,
    int* accountsColSize,
    int* returnSize,
    int** returnColSize
) {
    DisjointSet* ds = createDS(accountsSize);

    char** emailList = NULL;
    int* emailOwner = NULL;
    int emailCount = 0;

    /* Union accounts with common emails */
    for (int i = 0; i < accountsSize; i++) {
        for (int j = 1; j < accountsColSize[i]; j++) {
            char* email = accounts[i][j];
            int found = -1;

            for (int k = 0; k < emailCount; k++) {
                if (strcmp(emailList[k], email) == 0) {
                    found = k;
                    break;
                }
            }

            if (found != -1) {
                unionSet(ds, i, emailOwner[found]);
            } else {
                emailList = realloc(emailList, (emailCount + 1) * sizeof(char*));
                emailOwner = realloc(emailOwner, (emailCount + 1) * sizeof(int));
                emailList[emailCount] = email;
                emailOwner[emailCount] = i;
                emailCount++;
            }
        }
    }

    /* Group emails by root */
    char*** grouped = calloc(accountsSize, sizeof(char**));
    int* groupedSize = calloc(accountsSize, sizeof(int));

    for (int i = 0; i < emailCount; i++) {
        int root = findSet(ds, emailOwner[i]);
        grouped[root] = realloc(grouped[root], (groupedSize[root] + 1) * sizeof(char*));
        grouped[root][groupedSize[root]++] = emailList[i];
    }

    /* Build result */
    char*** result = NULL;
    *returnColSize = NULL;
    *returnSize = 0;

    for (int i = 0; i < accountsSize; i++) {
        if (groupedSize[i] == 0) continue;

        qsort(grouped[i], groupedSize[i], sizeof(char*), cmp);

        result = realloc(result, (*returnSize + 1) * sizeof(char**));
        *returnColSize = realloc(*returnColSize, (*returnSize + 1) * sizeof(int));

        int sz = groupedSize[i] + 1;
        result[*returnSize] = malloc(sz * sizeof(char*));
        result[*returnSize][0] = accounts[i][0];

        for (int j = 0; j < groupedSize[i]; j++)
            result[*returnSize][j + 1] = grouped[i][j];

        (*returnColSize)[*returnSize] = sz;
        (*returnSize)++;
    }

    return result;
}

