class DisjointSet {
    int[] parent, rank;

    DisjointSet(int n) {
        parent = new int[n];
        rank = new int[n];
        for (int i = 0; i < n; i++)
            parent[i] = i;
    }

    int find(int x) {
        if (parent[x] != x)
            parent[x] = find(parent[x]);
        return parent[x];
    }

    void union(int a, int b) {
        int pa = find(a);
        int pb = find(b);
        if (pa == pb) return;

        if (rank[pa] < rank[pb]) {
            parent[pa] = pb;
        } else if (rank[pa] > rank[pb]) {
            parent[pb] = pa;
        } else {
            parent[pb] = pa;
            rank[pa]++;
        }
    }
}

class Solution {

    public List<List<String>> mergeAccounts(List<List<String>> accountLists) {
        int n = accountLists.size();
        DisjointSet ds = new DisjointSet(n);

        Map<String, Integer> emailToIndex = new HashMap<>();

        // Union accounts sharing emails
        for (int i = 0; i < n; i++) {
            List<String> acc = accountLists.get(i);
            for (int j = 1; j < acc.size(); j++) {
                String email = acc.get(j);
                if (emailToIndex.containsKey(email)) {
                    ds.union(i, emailToIndex.get(email));
                } else {
                    emailToIndex.put(email, i);
                }
            }
        }

        // Group emails by root parent
        Map<Integer, TreeSet<String>> mergedEmails = new HashMap<>();
        for (Map.Entry<String, Integer> entry : emailToIndex.entrySet()) {
            int root = ds.find(entry.getValue());
            mergedEmails
                .computeIfAbsent(root, k -> new TreeSet<>())
                .add(entry.getKey());
        }

        // Build final result
        List<List<String>> result = new ArrayList<>();
        for (Map.Entry<Integer, TreeSet<String>> entry : mergedEmails.entrySet()) {
            int root = entry.getKey();
            List<String> merged = new ArrayList<>();
            merged.add(accountLists.get(root).get(0)); // name
            merged.addAll(entry.getValue());
            result.add(merged);
        }

        return result;
    }
}

