        this.parent = Array.from({ length: n }, (_, i) => i);
        this.rank = new Array(n).fill(0);
    }

    find(x) {
        if (this.parent[x] !== x)
            this.parent[x] = this.find(this.parent[x]);
        return this.parent[x];
    }

    union(a, b) {
        let pa = this.find(a);
        let pb = this.find(b);
        if (pa === pb) return;

        if (this.rank[pa] < this.rank[pb]) {
            this.parent[pa] = pb;
        } else if (this.rank[pa] > this.rank[pb]) {
            this.parent[pb] = pa;
        } else {
            this.parent[pb] = pa;
            this.rank[pa]++;
        }
    }
}

class Solution {
    mergeAccounts(accountLists) {
        const n = accountLists.length;
        const ds = new DisjointSet(n);

        const emailToIndex = new Map();

        // Union accounts sharing emails
        for (let i = 0; i < n; i++) {
            const acc = accountLists[i];
            for (let j = 1; j < acc.length; j++) {
                const email = acc[j];
                if (emailToIndex.has(email)) {
                    ds.union(i, emailToIndex.get(email));
                } else {
                    emailToIndex.set(email, i);
                }
            }
        }

        // Group emails by root parent
        const mergedEmails = new Map();
        for (const [email, idx] of emailToIndex.entries()) {
            const root = ds.find(idx);
            if (!mergedEmails.has(root))
                mergedEmails.set(root, new Set());
            mergedEmails.get(root).add(email);
        }

        // Build final result
        const result = [];
        for (const [root, emailSet] of mergedEmails.entries()) {
            const emails = Array.from(emailSet).sort();
            const merged = [accountLists[root][0], ...emails];
            result.push(merged);
        }

        return result;
    }
}
